import { useEffect, useState } from "react";
import { getGenres, getMoviesByGenreId } from "../../services/api";
import { useNavigate } from "react-router-dom";
import Navbar from "../../components/Navbar/Navbar";
import Footer from "../../components/Footer/Footer";
import "./GenrePage.css";

function GenrePage() {
  const [genres, setGenres] = useState([]);
  const [selectedGenre, setSelectedGenre] = useState(null);
  const [movies, setMovies] = useState([]);

  const navigate = useNavigate();

  // 🎬 ảnh cho từng genre
//   const genreImages = {
//     Action: "https://image.tmdb.org/t/p/original/8UlWHLMpgZm9bx6QYh0NFoq67TZ.jpg",
//     Comedy: "https://image.tmdb.org/t/p/original/9PkZesKMnblFfKxEhQx45YQ2kIe.jpg",
//     Horror: "https://image.tmdb.org/t/p/original/3CxUndGhUcZdt1Zggjdb2HkLLQX.jpg",
//     Romance: "https://image.tmdb.org/t/p/original/2EewmxXe72ogD0EaWM8gqa0ccIw.jpg",
//     Animation: "https://image.tmdb.org/t/p/original/sWvxBXNtCOaGdtpKNLiO2fhff2X.jpg",
//     Thriller: "https://image.tmdb.org/t/p/original/6EdKBYkB1ssgGjc249ud1L55o8d.jpg",
//     Drama: "https://image.tmdb.org/t/p/original/7VrRna8S3x6xbijooeBmxqvHXiu.jpg",
//     "Science Fiction": "https://image.tmdb.org/t/p/original/rAiYTfKGqDCRIIqo664sY9XZIvQ.jpg",
//     Fantasy: "https://image.tmdb.org/t/p/original/mqsPyyeDCBAghXyjbw4TfEYwljw.jpg",
//     Adventure: "https://image.tmdb.org/t/p/original/5YZbUmjbMa3ClvSW1Wj3D6XGolb.jpg"
//   };

  useEffect(() => {
    getGenres()
      .then(res => setGenres(res.data || []))
      .catch(err => console.error(err));
  }, []);

  const handleClickGenre = async (genre) => {
    setSelectedGenre(genre);

    try {
      const res = await getMoviesByGenreId(genre.id);
      setMovies(res.data || []);
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="genres-page">
      <Navbar />

      <h1 className="title">🎬 All Genres</h1>

      {/* ✅ NETFLIX STYLE GRID */}
      <div className="genre-grid">
        {genres.map(g => (
          <div
            key={g.id}
            className={`genre-card ${selectedGenre?.id === g.id ? "active" : ""}`}
            onClick={() => handleClickGenre(g)}
          >
            {/* <img
              src={genreImages[g.name] || "https://via.placeholder.com/300x200"}
              alt={g.name}
            /> */}

            <div className="overlay">
              <h3>{g.name}</h3>
            </div>
          </div>
        ))}
      </div>

      {/* MOVIES */}
      {selectedGenre && (
        <div className="movies-section">
          <h2>🔥 {selectedGenre.name}</h2>

          <div className="movies-grid">
            {movies.map(movie => (
              <div
                key={movie.id}
                className="movie-card"
                onClick={() => navigate(`/movies/${movie.id}`)}
              >
                <img src={movie.image} alt={movie.title} />
                <p>{movie.title}</p>
              </div>
            ))}
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
}

export default GenrePage;
